package com.hospital.management.controller.appointment;import com.hospital.management.service.AppointmentService;import org.junit.jupiter.api.Test;import javax.servlet.http.*;import java.io.*;import static org.junit.jupiter.api.Assertions.assertEquals;import static org.mockito.Mockito.*;
class AvailableSlotsServletValidationTest {@Test void wrongDateFormatReturns400()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=response();when(q.getParameter("doctorId")).thenReturn("2");when(q.getParameter("appointmentDate")).thenReturn("21/07/2026");new AvailableSlotsServlet(s).doGet(q,r);verify(r).setStatus(400);verifyNoInteractions(s);}@Test void missingDoctorReturns400()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=response();when(q.getParameter("appointmentDate")).thenReturn("2026-07-27");new AvailableSlotsServlet(s).doGet(q,r);verify(r).setStatus(400);verifyNoInteractions(s);}@Test void emptySlotsReturnEmptyJson()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);StringWriter body=new StringWriter();when(r.getWriter()).thenReturn(new PrintWriter(body));when(q.getParameter("doctorId")).thenReturn("2");when(q.getParameter("appointmentDate")).thenReturn("2026-07-30");when(s.getAvailableSlots(anyLong(),any(),isNull(),isNull())).thenReturn(java.util.List.of());new AvailableSlotsServlet(s).doGet(q,r);assertEquals("[]",body.toString());verify(r).setStatus(200);}private HttpServletResponse response()throws Exception{HttpServletResponse r=mock(HttpServletResponse.class);when(r.getWriter()).thenReturn(new PrintWriter(new StringWriter()));return r;}}
